code = """import json

# Get the data from previous queries - accessing via locals()
non_python_repos = [item for item in [locals().get('var_functions.query_db:6')] if item]
readme_files = [item for item in [locals().get('var_functions.query_db:10')] if item]

# The variables should be lists, let's debug
print('DEBUG: Non-python repos type:', type(non_python_repos))
print('DEBUG: Non-python repos length:', len(non_python_repos))
print('DEBUG: README files type:', type(readme_files))
print('DEBUG: README files length:', len(readme_files))

if non_python_repos and readme_files:
    non_python_names = set()
    for repo in non_python_repos[0]:
        if 'repo_name' in repo:
            non_python_names.add(repo['repo_name'])
    
    filtered_readmes = []
    for readme in readme_files[0]:
        if 'sample_repo_name' in readme and readme['sample_repo_name'] in non_python_names:
            filtered_readmes.append(readme)
    
    copyright_terms = ['copyright', 'Copyright', '©', '(c)', '(C)']
    copyright_count = 0
    
    for readme in filtered_readmes:
        content = readme.get('content', '') or ''
        if any(term in content for term in copyright_terms):
            copyright_count += 1
    
    total = len(filtered_readmes)
    proportion = copyright_count / total if total > 0 else 0
    
    result = {
        'non_python_repos': len(non_python_names),
        'readme_files': total,
        'copyright_found': copyright_count,
        'proportion': round(proportion, 4)
    }
    
    print('__RESULT__:')
    print(json.dumps(result))
else:
    print('__RESULT__:')
    print(json.dumps({'error': 'No data found'}))"""

